import { useEffect, useMemo, useState } from "react";
import { cn } from "../lib/utils";

export default function MobileTopNav({ sections }) {
  const [active, setActive] = useState(sections[0]?.id ?? null);

  const ids = useMemo(() => sections.map((s) => s.id), [sections]);

  useEffect(() => {
    const elements = ids
      .map((id) => document.getElementById(id))
      .filter((el) => Boolean(el));

    if (elements.length === 0) return;

    const handleInitial = () => {
      const byTop = [...elements].sort((a, b) => Math.abs(a.getBoundingClientRect().top) - Math.abs(b.getBoundingClientRect().top))[0];
      if (byTop?.id) setActive(byTop.id);
    };

    handleInitial();

    const observer = new IntersectionObserver(
      (entries) => {
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio)[0];
        if (visible?.target && visible.target.id) {
          setActive(visible.target.id);
        }
      },
      {
        root: null,
        rootMargin: "-45% 0px -45% 0px",
        threshold: [0.2, 0.4, 0.6, 0.8, 1],
      }
    );

    elements.forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, [ids]);

  const onClick = (id) => (e) => {
    e.preventDefault();
    const el = document.getElementById(id);
    if (!el) return;
    el.scrollIntoView({ behavior: "smooth", block: "start" });
    setActive(id);
  };

  return (
    <nav aria-label="Secciones" className="md:hidden sticky top-50 z-40 px-4">
      <div className="rounded-full border border-white/40 bg-white/70 backdrop-blur-md shadow-md supports-[backdrop-filter]:bg-white/60 px-2 py-2 overflow-x-auto">
        <ul className="flex items-center gap-1 whitespace-nowrap">
          {sections.map((s) => {
            const isActive = active === s.id;
            return (
              <li key={s.id}>
                <a
                  href={`#${s.id}`}
                  onClick={onClick(s.id)}
                  className={cn(
                    "group relative block px-3 py-1.5 rounded-full transition-all",
                    "text-xs font-medium",
                    isActive
                      ? "text-[#F29E38] scale-[1.03] bg-white ring-1 ring-[#F29E38]/40"
                      : "text-brand-dark/80 hover:text-brand-dark hover:bg-white/70"
                  )}
                >
                  <span className="relative">
                    {s.label}
                    <span
                      aria-hidden
                      className={cn(
                        "absolute -bottom-1 left-0 h-0.5 rounded-full bg-[#F29E38] transition-all",
                        isActive ? "w-full" : "w-0 group-hover:w-full"
                      )}
                    />
                  </span>
                </a>
              </li>
            );
          })}
        </ul>
      </div>
    </nav>
  );
}
